// Parse contact-form submission.
const raw = $input.first().json;
const body = raw.body || raw;
const out = {
  name: body.name || '',
  email: body.email || '',
  mobile_number: String(body.mobile_number || body.mobile || '').replace(/[^0-9]/g, '').replace(/^61/, '0').slice(-10),
  message: body.message || body.enquiry || '',
  stripe_subscription_id: body.stripe_subscription_id || '',
  stripe_customer_id: body.stripe_customer_id || ''
};
return [{ json: out }];

// Retention keyword detection.
const d = $json;
const keywords = ['cancel', 'cancelling', 'leaving', 'switching', 'cheaper', 'competitor', 'too expensive', 'not worth'];
const msg = String(d.message || '').toLowerCase();
const hits = keywords.filter((k) => msg.includes(k));
return [{ json: { ...d, retention: hits.length > 0, retention_keywords: hits } }];

// Apply the 10%_LOYALTY coupon (keZywUSF, 3 months repeating) to the customer's subscription.
const helpers = this.helpers;
const d = $json;
const auth = 'Bearer ' + $env.STRIPE_SECRET_KEY;
const COUPON = 'keZywUSF';
let subId = d.stripe_subscription_id;
if (!subId && d.stripe_customer_id) {
  const list = await helpers.httpRequest({ method: 'GET', url: 'https://api.stripe.com/v1/subscriptions?status=active&limit=1&customer=' + d.stripe_customer_id, headers: { Authorization: auth }, json: true });
  if (list.data && list.data[0]) subId = list.data[0].id;
}
let result = { skipped: true, reason: 'no subscription resolved from enquiry' };
if (subId) {
  result = await helpers.httpRequest({ method: 'POST', url: 'https://api.stripe.com/v1/subscriptions/' + subId, headers: { Authorization: auth, 'Content-Type': 'application/x-www-form-urlencoded' }, body: 'coupon=' + COUPON });
}
return [{ json: { ...d, loyalty_coupon_applied: result, subscription_id: subId } }];

// Loyalty SMS to the customer (ClickSend dedicated number - two-way).
const helpers = this.helpers;
const d = $json;
const to = d.mobile_number ? ('+61' + d.mobile_number.replace(/^0/, '')) : $env.OWNER_MOBILE;
const text = "We value your loyalty. We've applied a 10% discount to your next 3 months automatically.";
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: to, body: text }] }, json: true });
return [{ json: { ...d, loyalty_sms: resp } }];

// Flag the retention enquiry to the owner.
const helpers = this.helpers;
const d = $json;
const text = 'PRISONCALL RETENTION flagged. From: ' + (d.name || d.email || d.mobile_number || 'unknown') + '. Keywords: ' + (d.retention_keywords || []).join(', ') + '. 10% loyalty coupon auto-applied (sub ' + (d.subscription_id || 'n/a') + ').';
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] }, json: true });
return [{ json: { ...d, owner_flag_sms: resp } }];

// Pass the enquiry to Claude with the Prisoncall knowledge base. Expect JSON {reply, confidence}.
const helpers = this.helpers;
const d = $json;
const KB = 'Prisoncall Australia provides families a dedicated local phone number (DID) sourced from the telephone exchange closest to the prison. Prisoner calls that number at the local landline rate; the call diverts to the subscriber mobile. The SUBSCRIBER presses 1 to accept each call (prevents voicemail). Plans (AUD): Weekly $15, Fortnightly $25, Monthly $45, Quarterly $125. Coverage: VIC and NSW prisons only. The plan fee covers unlimited incoming calls/minutes; the prisoner still incurs the prison standard call charges. Subscribers manage billing via the Stripe customer portal (cancel, update payment method, invoice history). Bundle discount: 10% off when 2+ active plans share the same billing interval. Cancellation is immediate with a 5-day grace/reactivation window.';
const system = 'You are Prisoncall Australia customer support. Answer using ONLY the knowledge base. Be concise, warm and accurate. Respond STRICTLY as compact JSON on a single line: {"reply": "...", "confidence": 0.0-1.0}. Use confidence >= 0.8 ONLY when the knowledge base clearly and fully answers; otherwise lower. Knowledge base: ' + KB;
let text = '';
try {
  const resp = await helpers.httpRequest({ method: 'POST', url: 'https://api.anthropic.com/v1/messages', headers: { 'x-api-key': $env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' }, body: { model: 'claude-sonnet-4-20250514', max_tokens: 600, system: system, messages: [{ role: 'user', content: String(d.message || '') }] }, json: true });
  text = (resp.content && resp.content[0] && resp.content[0].text) || '';
} catch (e) { text = ''; }
let parsed = { reply: text, confidence: 0 };
try { parsed = JSON.parse(text); } catch (e) { parsed = { reply: text || 'Thanks for your message - our team will get back to you shortly.', confidence: 0.2 }; }
return [{ json: { ...d, ai_reply: parsed.reply, ai_confidence: Number(parsed.confidence) || 0, claude_raw: text } }];

// Low AI confidence - flag the enquiry to the owner for manual handling.
const helpers = this.helpers;
const d = $json;
const text = 'PRISONCALL support enquiry flagged (low AI confidence ' + d.ai_confidence + '). From: ' + (d.name || d.email || d.mobile_number || 'unknown') + '. Message: ' + String(d.message || '').slice(0, 200);
const auth = 'Basic ' + Buffer.from($env.CLICKSEND_USERNAME + ':' + $env.CLICKSEND_API_KEY).toString('base64');
const resp = await helpers.httpRequest({ method: 'POST', url: 'https://rest.clicksend.com/v3/sms/send', headers: { Authorization: auth, 'Content-Type': 'application/json' }, body: { messages: [{ source: 'n8n', from: $env.CLICKSEND_DEDICATED_NUMBER, to: $env.OWNER_MOBILE, body: text }] }, json: true });
return [{ json: { ...d, owner_flag_sms: resp } }];
